value.code:
resource "aws_instance" "web_server" {
  ami           = "ami-123456"
  instance_type = "t3.micro"

  tags = {
    Name = "web-server"
  }
}

variable "aws_region" {
  type    = string
  default = "us-east-1"
}

output "public_dns" {
  value = aws_instance.web_server.public_dns
}

variable "aws_region" {
  type        = string
  description = "Default AWS region for this configuration, for example us-east-1"
  default     = "us-east-1"
}

variable "api_key" {
  type        = string
  description = "API key used by the application"
  sensitive   = true
}

provider "aws" {
  region = var.aws_region
}

resource "aws_instance" "web" {
  instance_type = var.instance_type
}

variable "allowed_ports" {
  type = list(number)
}

variable "subnet_cidrs" {
  type = map(list(string))
}

variable "vpc_config" {
  type = object({
    name               = string
    subnets            = map(string)
    create_nat_gateway = bool
  })
}

variable "vpc_region" {
  type        = string
  description = "Region for the VPC"
  nullable    = false
}

locals {
  naming_prefix = "${var.project}-${var.environment}"

  default_tags = merge(var.tags, {
    Project     = var.project
    Environment = var.environment
  })

  instance_name = "${local.naming_prefix}-web"
}

output "ec2_public_dns" {
  description = "Public DNS name of the application server"
  value       = aws_instance.web.public_dns
}

moved {
  from = aws_instance.web
  to   = aws_instance.app
}

removed {
  from = aws_instance.web

  lifecycle {
    destroy = false
  }
}

removed {
  from = aws_security_group.web

  lifecycle {
    destroy = false
  }
}

terraform {
  backend "s3" {
    key          = "nacho_brigade/terraform.tfstate"
    use_lockfile = true
  }
}

locals {
  environment = terraform.workspace == "default" ? var.environment : terraform.workspace
}

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 6.13.0"
    }

    random = {
      source  = "hashicorp/random"
      version = "~> 3.7.0"
    }
  }
}

provider "aws" {
  region = var.region
}

terraform {
  required_providers {
    random = {
      source  = "hashicorp/random"
      version = "= 2.3.1"
    }
  }
}

resource "random_string" "bucket_suffix" {
  length  = 12
  special = false
  upper   = false
}

provider_installation {
  filesystem_mirror {
    path    = "/path/to/provider-mirror"
    include = ["registry.terraform.io/hashicorp/*"]
  }
}

plugin_cache_dir = "/path/to/plugin-cache"

provider "aws" {
  region = var.region
}

# Alternative style using provider arguments
provider "aws" {
  region     = var.region
  access_key = var.aws_access_key
  secret_key = var.aws_secret_key
}

provider "aws" {
  region = var.region
}

provider "aws" {
  alias  = "dr"
  region = var.dr_region
}

module "dr_vpc" {
  source = "./modules/vpc"

  providers = {
    aws = aws.dr
  }

  region = var.dr_region
}

provider "aws" {
  region = var.region
}

provider "aws" {
  alias  = "security"
  region = var.region

  assume_role {
    role_arn = var.security_role_arn
  }
}

module "prod_s3_bucket" {
  source = "./modules/vpc_flow_logs"

  providers = {
    aws             = aws.security
    aws.vpc_account = aws
  }

  vpc_id           = module.prod_vpc.vpc_id
  naming_prefix    = "sopes-saloon"
  bucket_id_suffix = random_string.bucket_suffix.result
  iam_role_arn     = var.security_role_arn
}

variable "vpc_id" {
  description = "ID of the VPC where resources will be created"
  type        = string
}

variable "public_subnet_ids" {
  description = "Public subnet IDs used by the load balancer and autoscaling group"
  type        = list(string)
}

output "autoscaling_group_name" {
  description = "Name of the autoscaling group"
  value       = aws_autoscaling_group.web.name
}

output "lb_public_dns" {
  description = "Public DNS name of the load balancer"
  value       = aws_lb.web.dns_name
}

provider "aws" {
  region = "us-west-2"
}

provider "aws" {
  alias  = "security"
  region = "us-east-1"
}

module "security_stack" {
  source = "./modules/security-stack"

  providers = {
    aws = aws.security
  }
}

variable "instance_tags" {
  description = "Additional tags applied to EC2 instances"
  type        = map(string)
  default     = {}
}

# inside the launch template tags
merge(
  {
    Name        = var.prefix
    Environment = var.environment
  },
  var.instance_tags
)
